	for i := 0; i < 32; i++ {
		w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysYield))
	}

	openRetry := pc
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	w(ie64Instr(OP_ADD, 1, IE64_SIZE_L, 1, 29, 0, 0x180))
	w(ie64Instr(OP_MOVE, 2, IE64_SIZE_L, 1, 0, 0, version))
