// newIExecTerminalRig creates a test rig with terminal MMIO mapped.
func newIExecTerminalRig(t *testing.T) (*ie64TestRig, *TerminalMMIO) {
	t.Helper()
	rig := newIE64TestRig()
	term := NewTerminalMMIO()
	rig.bus.MapIO(TERM_OUT, TERMINAL_REGION_END, term.HandleRead, term.HandleWrite)
	return rig, term
}

// assembleAndLoadKernel builds ie64asm, assembles iexec.s, loads the binary into a rig with terminal.
func assembleAndLoadKernel(t *testing.T) (*ie64TestRig, *TerminalMMIO) {
	return assembleAndLoadKernelWithGeneratedHostRoot(t)
}

// Guest paths for the two bootstrap-HostFS specials the harness installs.
const (
	specialConsolePath = "IOSSYS/L/console.handler"
	specialShellPath   = "IOSSYS/Tools/Shell"
)

// installBootServiceSpecials installs the console.handler and Shell ELFs as
// live-aliased HostFS specials backed by their reserved guest-memory regions.
// The live alias lets a test patch the ELF bytes in place and have the
// bootstrap path observe the patch.
func installBootServiceSpecials(t *testing.T, hostfs *BootstrapHostFSDevice, mem []byte) {
	t.Helper()
	consoleImage := mustReadRepoBytes(t, bootConsoleELFPath)
	copy(mem[int(testHostConsoleELFBase):], consoleImage)
	hostfs.SetSpecialFileLive(specialConsolePath, mem[int(testHostConsoleELFBase):int(testHostConsoleELFBase)+len(consoleImage)])
	shellImage := mustReadRepoBytes(t, bootShellELFPath)
	copy(mem[int(testHostShellELFBase):], shellImage)
	hostfs.SetSpecialFileLive(specialShellPath, mem[int(testHostShellELFBase):int(testHostShellELFBase)+len(shellImage)])
}

// installSyntheticCommandImages keeps stable in-memory copies of the shipped
// command ELFs so findAllProgramImages can still return the full runtime set
// after commands moved out of the assembled kernel image.
func installSyntheticCommandImages(t *testing.T, mem []byte) {
	t.Helper()
	for i, rel := range cmdELFPaths {
		base := testHostCmdELFBase + uint32(i)*testHostCmdELFStride
		image := mustReadRepoBytes(t, rel)
		if len(image) > int(testHostCmdELFStride) {
			t.Fatalf("installSyntheticCommandImages: %s size %d exceeds slot size %d", rel, len(image), testHostCmdELFStride)
		}
		slot := mem[int(base) : int(base)+int(testHostCmdELFStride)]
		clear(slot)
		copy(slot, image)
	}
}

func assembleAndLoadKernelWithGeneratedHostRoot(t *testing.T) (*ie64TestRig, *TerminalMMIO) {
	t.Helper()
	return assembleAndLoadKernelWithBootstrapHostRootOptions(t, makeM152Phase5GeneratedHostRoot(t), true)
}

func assembleAndLoadKernelWithBootstrapHostRoot(t *testing.T, hostRoot string) (*ie64TestRig, *TerminalMMIO) {
	return assembleAndLoadKernelWithBootstrapHostRootOptions(t, hostRoot, false)
}

func assembleAndLoadKernelWithBootstrapHostRootOptions(t *testing.T, hostRoot string, useSpecialBootServices bool) (*ie64TestRig, *TerminalMMIO) {
	return assembleAndLoadKernelWithBootstrapHostRootDefinesAndMutator(t, hostRoot, useSpecialBootServices, nil, nil)
}

func assembleAndLoadKernelWithBootstrapHostRootDefines(t *testing.T, hostRoot string, useSpecialBootServices bool, defines []string) (*ie64TestRig, *TerminalMMIO) {
	return assembleAndLoadKernelWithBootstrapHostRootDefinesAndMutator(t, hostRoot, useSpecialBootServices, defines, nil)
}

func assembleAndLoadKernelWithBootstrapHostRootDefinesAndMutator(t *testing.T, hostRoot string, useSpecialBootServices bool, defines []string, mutate func(*BootstrapHostFSDevice, []byte)) (*ie64TestRig, *TerminalMMIO) {
	t.Helper()
	asmBin := buildAssembler(t)
	tmpDir := t.TempDir()
	root := repoRootDir(t)
	copyFileForTest(t, filepath.Join(root, "sdk", "intuitionos", "iexec", "iexec.s"), filepath.Join(tmpDir, "iexec.s"))
	copyFileForTest(t, filepath.Join(root, "sdk", "include", "iexec.inc"), filepath.Join(tmpDir, "iexec.inc"))
	copyFileForTest(t, filepath.Join(root, "sdk", "include", "ie64.inc"), filepath.Join(tmpDir, "ie64.inc"))
	// M12: About app uses `incbin "topaz.raw"` for its bitmap font.
	copyFileForTest(t, filepath.Join(root, "sdk", "include", "topaz.raw"), filepath.Join(tmpDir, "topaz.raw"))
	iexecSrcDir := filepath.Join(root, "sdk", "intuitionos", "iexec")
	args := []string{"-I", tmpDir, "-I", iexecSrcDir}
	for _, define := range defines {
		args = append(args, "-D", define)
	}
	args = append(args, filepath.Join(tmpDir, "iexec.s"))
	cmd := exec.Command(asmBin, args...)
	if out, err := cmd.CombinedOutput(); err != nil {
		t.Fatalf("assembly failed: %v\n%s", err, out)
	}

	data, err := os.ReadFile(filepath.Join(tmpDir, "iexec.ie64"))
	if err != nil {
		t.Fatalf("read assembled binary: %v", err)
	}

	rig, term := newIExecTerminalRig(t)
	hostfs := NewBootstrapHostFSDevice(rig.bus, hostRoot)
	installSyntheticCommandImages(t, rig.cpu.memory)
	if useSpecialBootServices {
		installBootServiceSpecials(t, hostfs, rig.cpu.memory)
	}
	if mutate != nil {
		mutate(hostfs, rig.cpu.memory)
	}
	rig.bus.MapIO(BOOT_HOSTFS_BASE, BOOT_HOSTFS_END, hostfs.HandleRead, hostfs.HandleWrite)
	copy(rig.cpu.memory[PROG_START:], data)
	m164InstallLegacyTask0Seed(rig.cpu.memory)
	rig.cpu.PC = PROG_START
	rig.cpu.CoprocMode = true
	return rig, term
}

func assembleAndLoadKernelWithBootstrapHostFSDevice(t *testing.T, device interface {
	HandleRead(uint32) uint32
	HandleWrite(uint32, uint32)
}) (*ie64TestRig, *TerminalMMIO) {
	t.Helper()
	asmBin := buildAssembler(t)
	tmpDir := t.TempDir()
	root := repoRootDir(t)
	copyFileForTest(t, filepath.Join(root, "sdk", "intuitionos", "iexec", "iexec.s"), filepath.Join(tmpDir, "iexec.s"))
	copyFileForTest(t, filepath.Join(root, "sdk", "include", "iexec.inc"), filepath.Join(tmpDir, "iexec.inc"))
	copyFileForTest(t, filepath.Join(root, "sdk", "include", "ie64.inc"), filepath.Join(tmpDir, "ie64.inc"))
	copyFileForTest(t, filepath.Join(root, "sdk", "include", "topaz.raw"), filepath.Join(tmpDir, "topaz.raw"))
	iexecSrcDir := filepath.Join(root, "sdk", "intuitionos", "iexec")
	cmd := exec.Command(asmBin, "-I", tmpDir, "-I", iexecSrcDir, filepath.Join(tmpDir, "iexec.s"))
	if out, err := cmd.CombinedOutput(); err != nil {
		t.Fatalf("assembly failed: %v\n%s", err, out)
	}
	data, err := os.ReadFile(filepath.Join(tmpDir, "iexec.ie64"))
	if err != nil {
		t.Fatalf("read assembled binary: %v", err)
	}
	rig, term := newIExecTerminalRig(t)
	installSyntheticCommandImages(t, rig.cpu.memory)
	if hostfs, ok := device.(*BootstrapHostFSDevice); ok {
		installBootServiceSpecials(t, hostfs, rig.cpu.memory)
	}
	if hostfs, ok := device.(*failingBootstrapHostFSDevice); ok && hostfs.BootstrapHostFSDevice != nil {
		installBootServiceSpecials(t, hostfs.BootstrapHostFSDevice, rig.cpu.memory)
	}
	rig.bus.MapIO(BOOT_HOSTFS_BASE, BOOT_HOSTFS_END, device.HandleRead, device.HandleWrite)
	copy(rig.cpu.memory[PROG_START:], data)
	m164InstallLegacyTask0Seed(rig.cpu.memory)
	rig.cpu.PC = PROG_START
	rig.cpu.CoprocMode = true
	return rig, term
}

type failingBootstrapHostFSDevice struct {
	*BootstrapHostFSDevice
	failOpenPath                 string
	failReadPath                 string
	forceMissingExceptBootDoslib bool
	mu                           sync.Mutex
	handlePath                   map[uint32]string
	statObs                      []hostFSStatObservation
}

type hostFSStatObservation struct {
	path     string
	taskSlot uint32
	arg1     uint32
	ptbr     uint64
	pte      uint64
	pteFlags byte
}

func newFailingBootstrapHostFSDevice(bus *MachineBus, hostRoot string) *failingBootstrapHostFSDevice {
	return &failingBootstrapHostFSDevice{
		BootstrapHostFSDevice: NewBootstrapHostFSDevice(bus, hostRoot),
		handlePath:            make(map[uint32]string),
	}
}

func (d *failingBootstrapHostFSDevice) recordOpenHandle(handle uint32, path string) {
	d.mu.Lock()
	defer d.mu.Unlock()
	d.handlePath[handle] = path
}

func (d *failingBootstrapHostFSDevice) handleOpenPath(handle uint32) string {
	d.mu.Lock()
	defer d.mu.Unlock()
	return d.handlePath[handle]
}

func (d *failingBootstrapHostFSDevice) clearOpenHandle(handle uint32) {
	d.mu.Lock()
	defer d.mu.Unlock()
	delete(d.handlePath, handle)
}

func (d *failingBootstrapHostFSDevice) recordStatObservation(obs hostFSStatObservation) {
	d.mu.Lock()
	defer d.mu.Unlock()
	d.statObs = append(d.statObs, obs)
}

func (d *failingBootstrapHostFSDevice) statObservationsSnapshot() []hostFSStatObservation {
	d.mu.Lock()
	defer d.mu.Unlock()
	return append([]hostFSStatObservation(nil), d.statObs...)
}

func (d *failingBootstrapHostFSDevice) HandleWrite(addr uint32, val uint32) {
	switch addr {
	case BOOT_HOSTFS_ARG1:
		d.arg1 = val
	case BOOT_HOSTFS_ARG2:
		d.arg2 = val
	case BOOT_HOSTFS_ARG3:
		d.arg3 = val
	case BOOT_HOSTFS_ARG4:
		d.arg4 = val
	case BOOT_HOSTFS_CMD:
		d.res1 = 0
		d.res2 = 0
		d.err = 0
		switch val {
		case BOOT_HOSTFS_OPEN:
			path := d.readCString(d.arg1, 255)
			if d.forceMissingExceptBootDoslib &&
				!strings.EqualFold(path, "IOSSYS/LIBS/dos.library") &&
				!strings.EqualFold(path, specialConsolePath) {
				d.err = errNotFound
				return
			}
			if d.failOpenPath != "" && strings.EqualFold(path, d.failOpenPath) {
				d.err = errPerm
				return
			}
			d.open()
			if d.err == 0 && d.res1 != 0 {
				d.recordOpenHandle(d.res1, path)
			}
		case BOOT_HOSTFS_READ:
			if d.failReadPath != "" && strings.EqualFold(d.handleOpenPath(d.arg1), d.failReadPath) {
				d.err = errPerm
				return
			}
			d.read()
		case BOOT_HOSTFS_CLOSE:
			d.clearOpenHandle(d.arg1)
			d.close()
		case BOOT_HOSTFS_DISCOVER:
			if d.forceMissingExceptBootDoslib {
				d.err = errNotFound
				return
			}
			if !d.available {
				d.err = errNotFound
				return
			}
			d.res1 = 1
		case BOOT_HOSTFS_STAT:
			obs := hostFSStatObservation{
				path: d.readCString(d.arg1, 255),
				arg1: d.arg1,
			}
			slot := d.currentTaskSlot()
			obs.taskSlot = slot
			ptbr := uint64(0)
			pte := uint64(0)
			pteFlags := byte(0)
			if ptbr32, ok := d.currentTaskPTBR(); ok {
				ptbr = uint64(ptbr32)
				if ptbr32 != 0 {
					// d.arg1 is uint32; its VPN fits in 20 bits, well below PTE_PPN_MASK.
					pteAddr := uint32(ptbr) + ((d.arg1 >> MMU_PAGE_SHIFT) * 8)
					if int(pteAddr+8) <= len(d.bus.memory) {
						pte = binary.LittleEndian.Uint64(d.bus.memory[pteAddr:])
						_, pteFlags = parsePTE(pte)
					}
				}
			}
			obs.ptbr = ptbr
			obs.pte = pte
			obs.pteFlags = pteFlags
			d.recordStatObservation(obs)
			d.stat()
		case BOOT_HOSTFS_READDIR:
			d.readDir()
		default:
			d.err = 3
		}
	}
}

const (
	bootConsoleELFPath = "sdk/intuitionos/iexec/boot_console_handler.elf"
	bootShellELFPath   = "sdk/intuitionos/iexec/boot_shell.elf"
)

var cmdELFPaths = []string{
	"sdk/intuitionos/iexec/cmd_version.elf",
	"sdk/intuitionos/iexec/cmd_avail.elf",
	"sdk/intuitionos/iexec/cmd_dir.elf",
	"sdk/intuitionos/iexec/cmd_type.elf",
	"sdk/intuitionos/iexec/cmd_echo.elf",
	"sdk/intuitionos/iexec/cmd_resident.elf",
	"sdk/intuitionos/iexec/cmd_assign.elf",
	"sdk/intuitionos/iexec/cmd_list.elf",
	"sdk/intuitionos/iexec/cmd_which.elf",
	"sdk/intuitionos/iexec/cmd_help.elf",
	"sdk/intuitionos/iexec/cmd_gfxdemo.elf",
	"sdk/intuitionos/iexec/cmd_about.elf",
}

// bootTaskELFPaths: console handler + shell, launched outside the command namespace.
var bootTaskELFPaths = []string{bootConsoleELFPath, bootShellELFPath}

// embeddedRuntimeELFPaths: logical order used by the harness — console, commands, shell.
var embeddedRuntimeELFPaths = append(append([]string{bootConsoleELFPath}, cmdELFPaths...), bootShellELFPath)

// embeddedRuntimeELFPathsPhysical: order inside the assembled kernel image — boot tasks, then commands.
var embeddedRuntimeELFPathsPhysical = append([]string{bootConsoleELFPath, bootShellELFPath}, cmdELFPaths...)

const elfMagicLE uint32 = 0x464C457F

func elfExecCodeOffset(t *testing.T, image []byte) uint32 {
	t.Helper()
	if len(image) < 64 || binary.LittleEndian.Uint32(image[:4]) != elfMagicLE {
		t.Fatal("elfExecCodeOffset: image is not an ELF file")
	}
	phoff := binary.LittleEndian.Uint64(image[32:40])
	phentsize := binary.LittleEndian.Uint16(image[54:56])
	phnum := binary.LittleEndian.Uint16(image[56:58])
	for i := uint16(0); i < phnum; i++ {
		base := phoff + uint64(i)*uint64(phentsize)
		if base+56 > uint64(len(image)) {
			t.Fatal("elfExecCodeOffset: program header out of range")
		}
		if binary.LittleEndian.Uint32(image[base:]) != 1 {
			continue
		}
		flags := binary.LittleEndian.Uint32(image[base+4:])
		if flags&m14ELFSegFlagX == 0 {
			continue
		}
		return uint32(binary.LittleEndian.Uint64(image[base+8:]))
	}
	t.Fatal("elfExecCodeOffset: executable PT_LOAD segment not found")
	return 0
}

func elfExecCodeVA(t *testing.T, image []byte) uint32 {
	t.Helper()
	if len(image) < 64 || binary.LittleEndian.Uint32(image[:4]) != elfMagicLE {
		t.Fatal("elfExecCodeVA: image is not an ELF file")
	}
	phoff := binary.LittleEndian.Uint64(image[32:40])
	phentsize := binary.LittleEndian.Uint16(image[54:56])
	phnum := binary.LittleEndian.Uint16(image[56:58])
	for i := uint16(0); i < phnum; i++ {
		base := phoff + uint64(i)*uint64(phentsize)
		if base+56 > uint64(len(image)) {
			t.Fatal("elfExecCodeVA: program header out of range")
		}
		if binary.LittleEndian.Uint32(image[base:]) != 1 {
			continue
		}
		flags := binary.LittleEndian.Uint32(image[base+4:])
		if flags&m14ELFSegFlagX == 0 {
			continue
		}
		return uint32(binary.LittleEndian.Uint64(image[base+16:]))
	}
	t.Fatal("elfExecCodeVA: executable PT_LOAD segment not found")
	return 0
}

func elfWritableSegmentFileOffsetAndVA(t *testing.T, image []byte) (uint32, uint32) {
	t.Helper()
	if len(image) < 64 || binary.LittleEndian.Uint32(image[:4]) != elfMagicLE {
		t.Fatal("elfWritableSegmentFileOffsetAndVA: image is not an ELF file")
	}
	phoff := binary.LittleEndian.Uint64(image[32:40])
	phentsize := binary.LittleEndian.Uint16(image[54:56])
	phnum := binary.LittleEndian.Uint16(image[56:58])
	for i := uint16(0); i < phnum; i++ {
		base := phoff + uint64(i)*uint64(phentsize)
		if base+56 > uint64(len(image)) {
			t.Fatal("elfWritableSegmentFileOffsetAndVA: program header out of range")
		}
		if binary.LittleEndian.Uint32(image[base:]) != 1 {
			continue
		}
		flags := binary.LittleEndian.Uint32(image[base+4:])
		if flags&m14ELFSegFlagW == 0 {
			continue
		}
		return uint32(binary.LittleEndian.Uint64(image[base+8:])), uint32(binary.LittleEndian.Uint64(image[base+16:]))
	}
	t.Fatal("elfWritableSegmentFileOffsetAndVA: writable PT_LOAD segment not found")
	return 0, 0
}

func imageHeaderStartForCodeStart(t *testing.T, mem []byte, imageCodeStart uint32) (uint32, bool) {
	t.Helper()
	if imageCodeStart >= 0x1000 && binary.LittleEndian.Uint32(mem[imageCodeStart-0x1000:]) == elfMagicLE {
		return imageCodeStart - 0x1000, true
	}
	if imageCodeStart >= 32 {
		var magic [8]byte
		binary.LittleEndian.PutUint32(magic[0:4], 0x34364549)
		binary.LittleEndian.PutUint32(magic[4:8], 0x474F5250)
		header := imageCodeStart - 32
		if bytes.Equal(mem[header:header+8], magic[:]) {
			return header, false
		}
	}
	t.Fatalf("imageHeaderStartForCodeStart: could not identify image format at code start 0x%X", imageCodeStart)
	return 0, false
}

func imageCodeSizeForCodeStart(t *testing.T, mem []byte, imageCodeStart uint32) uint32 {
	t.Helper()
	header, isELF := imageHeaderStartForCodeStart(t, mem, imageCodeStart)
	if !isELF {
		return binary.LittleEndian.Uint32(mem[header+8:])
	}
	phoff := binary.LittleEndian.Uint64(mem[header+32:])
	phentsize := binary.LittleEndian.Uint16(mem[header+54:])
	phnum := binary.LittleEndian.Uint16(mem[header+56:])
	for i := uint16(0); i < phnum; i++ {
		base := header + uint32(phoff) + uint32(i)*uint32(phentsize)
		if binary.LittleEndian.Uint32(mem[base:]) != 1 {
			continue
		}
		flags := binary.LittleEndian.Uint32(mem[base+4:])
		if flags&m14ELFSegFlagX == 0 {
			continue
		}
		return uint32(binary.LittleEndian.Uint64(mem[base+32:]))
	}
	t.Fatalf("imageCodeSizeForCodeStart: executable PT_LOAD not found at 0x%X", imageCodeStart)
	return 0
}

func imageDataFileOffsetForCodeStart(t *testing.T, mem []byte, imageCodeStart uint32) uint32 {
	t.Helper()
	header, isELF := imageHeaderStartForCodeStart(t, mem, imageCodeStart)
	if !isELF {
		return imgHeaderSize + imageCodeSizeForCodeStart(t, mem, imageCodeStart)
	}
	phoff := binary.LittleEndian.Uint64(mem[header+32:])
	phentsize := binary.LittleEndian.Uint16(mem[header+54:])
	phnum := binary.LittleEndian.Uint16(mem[header+56:])
	for i := uint16(0); i < phnum; i++ {
		base := header + uint32(phoff) + uint32(i)*uint32(phentsize)
		if binary.LittleEndian.Uint32(mem[base:]) != 1 {
			continue
		}
		flags := binary.LittleEndian.Uint32(mem[base+4:])
		if flags&m14ELFSegFlagW == 0 {
			continue
		}
		return uint32(binary.LittleEndian.Uint64(mem[base+8:]))
	}
	t.Fatalf("imageDataFileOffsetForCodeStart: writable PT_LOAD not found at 0x%X", imageCodeStart)
	return 0
}

// findProgramImagesByPaths locates each ELF named in physicalPaths inside the
// assembled kernel image and returns the code-start offset of each one in
// the order given by orderedPaths. If an image was installed as a HostFS
// special backed by a reserved guest-memory region (console handler or
// shell), its code-start is taken from that region rather than by scanning
// the kernel image.
func tryFindProgramImagesByPaths(t *testing.T, mem []byte, physicalPaths []string, orderedPaths []string) ([]uint32, error) {
	t.Helper()
	search := mem[PROG_START:]
	searchBase := uint32(PROG_START)
	byPath := make(map[string]uint32, len(physicalPaths))
	for _, rel := range physicalPaths {
		image, err := os.ReadFile(repoPath(rel))
		if err != nil {
			return nil, fmt.Errorf("findProgramImagesByPaths: ReadFile(%q): %w", rel, err)
		}
		resolved := false
		if rel == bootConsoleELFPath {
			if binary.LittleEndian.Uint32(mem[testHostConsoleELFBase:]) == elfMagicLE {
				byPath[rel] = testHostConsoleELFBase + elfExecCodeOffset(t, image)
				resolved = true
			}
		}
		if !resolved && rel == bootShellELFPath {
			if binary.LittleEndian.Uint32(mem[testHostShellELFBase:]) == elfMagicLE {
				byPath[rel] = testHostShellELFBase + elfExecCodeOffset(t, image)
				resolved = true
			}
		}
		if !resolved {
			for i, cmdRel := range cmdELFPaths {
				if rel != cmdRel {
					continue
				}
				base := testHostCmdELFBase + uint32(i)*testHostCmdELFStride
				if binary.LittleEndian.Uint32(mem[base:]) == elfMagicLE {
					byPath[rel] = base + elfExecCodeOffset(t, image)
					resolved = true
				}
				break
			}
		}
		if resolved {
			continue
		}
		idx := bytes.Index(search, image)
		if idx < 0 {
			return nil, fmt.Errorf("findProgramImagesByPaths: could not locate %q in assembled kernel image", rel)
		}
		codeOff := elfExecCodeOffset(t, image)
		abs := searchBase + uint32(idx)
		byPath[rel] = abs + codeOff
		next := idx + len(image)
		searchBase += uint32(next)
		search = search[next:]
	}

	var codeStarts []uint32
	for _, rel := range orderedPaths {
		codeStart, ok := byPath[rel]
		if !ok {
			return nil, fmt.Errorf("findProgramImagesByPaths: missing resolved code start for %q", rel)
		}
		codeStarts = append(codeStarts, codeStart)
	}
	return codeStarts, nil
}

func findProgramImagesByPaths(t *testing.T, mem []byte, physicalPaths []string, orderedPaths []string) []uint32 {
	t.Helper()
	codeStarts, err := tryFindProgramImagesByPaths(t, mem, physicalPaths, orderedPaths)
	if err != nil {
		t.Fatal(err)
	}
	return codeStarts
}

func findAllProgramImages(t *testing.T, mem []byte) []uint32 {
	t.Helper()
	codeStarts, err := tryFindProgramImagesByPaths(t, mem, embeddedRuntimeELFPathsPhysical, embeddedRuntimeELFPaths)
	if err != nil {
		t.Fatalf("findAllProgramImages: %v", err)
	}
	return codeStarts
}

func findBootTaskImages(t *testing.T, mem []byte) []uint32 {
	t.Helper()
	return findProgramImagesByPaths(t, mem, bootTaskELFPaths, bootTaskELFPaths)
}

func repoPath(rel string) string {
	if filepath.IsAbs(rel) {
		return rel
	}
	_, file, _, ok := runtime.Caller(0)
	if !ok {
		return rel
	}
	return filepath.Join(filepath.Dir(file), rel)
}

// findTaskTemplates finds the code-start offsets of the first two bundled
// runtime ELF artifacts in the assembled kernel binary.
// Returns absolute memory addresses.
func findTaskTemplates(t *testing.T, mem []byte) (t0Start, t1Start uint32) {
	t.Helper()
	images := findBootTaskImages(t, mem)
	if len(images) < 2 {
		t.Fatalf("findTaskTemplates: found %d images, need at least 2", len(images))
	}
	return images[0], images[1]
}

func findTaskRegionRowByVA(t *testing.T, mem []byte, taskID uint64, va uint64) uint32 {
	t.Helper()

	inlineBase := uint32(kernDataBase + kdRegionTable + uint32(taskID)*kdRegionTaskSz)
	for i := uint32(0); i < kdRegionMax; i++ {
		row := inlineBase + i*kdRegionStride
		if mem[row+kdRegType] == regionFree {
			continue
		}
		if uint64(binary.LittleEndian.Uint32(mem[row+kdRegVA:])) == va {
			return row
		}
	}

	oflowHdr := uint32(kernDataBase + kdRegionOflowHead + uint32(taskID)*kdRegionOflowStride)
	ppn := binary.LittleEndian.Uint16(mem[oflowHdr+kdRegionOflowFirst:])
	for ppn != 0 {
		page := uint32(ppn) << 12
		row := page + kdRegionPageHdrSz
		for i := uint32(0); i < kdRegionRowsPerPg; i++ {
			if mem[row+kdRegType] != regionFree && uint64(binary.LittleEndian.Uint32(mem[row+kdRegVA:])) == va {
				return row
			}
			row += kdRegionStride
		}
		ppn = binary.LittleEndian.Uint16(mem[page+kdRegionPageNext:])
	}

	t.Fatalf("findTaskRegionRowByVA: no region row for task=%d va=0x%X", taskID, va)
	return 0
}

func findEmbeddedELFCodeStartLast(t *testing.T, mem []byte, rel string) uint32 {
	t.Helper()
	image, err := os.ReadFile(rel)
	if err != nil {
		t.Fatalf("findEmbeddedELFCodeStartLast: ReadFile(%q): %v", rel, err)
	}
	idx := bytes.LastIndex(mem[PROG_START:], image)
	if idx < 0 {
		t.Fatalf("findEmbeddedELFCodeStartLast: could not locate %q in assembled kernel image", rel)
	}
	return PROG_START + uint32(idx) + elfExecCodeOffset(t, image)
}

func findEmbeddedBlobStartLast(t *testing.T, mem []byte, rel string) (uint32, uint32) {
	t.Helper()
	image, err := os.ReadFile(rel)
	if err != nil {
		t.Fatalf("findEmbeddedBlobStartLast: ReadFile(%q): %v", rel, err)
	}
	idx := bytes.LastIndex(mem[PROG_START:], image)
	if idx < 0 {
		t.Fatalf("findEmbeddedBlobStartLast: could not locate %q in assembled kernel image", rel)
	}
	return PROG_START + uint32(idx), uint32(len(image))
}

func findShellClientCodeStart(t *testing.T, mem []byte) uint32 {
	t.Helper()
	image, err := os.ReadFile(repoPath("sdk/intuitionos/iexec/boot_shell.elf"))
	if err != nil {
		t.Fatalf("findShellClientCodeStart: ReadFile(%q): %v", "sdk/intuitionos/iexec/boot_shell.elf", err)
	}
	return testHostShellELFBase + elfExecCodeOffset(t, image)
}

// yieldLoopOverride writes a YIELD + BRA -8 loop at the given address,
// turning whatever program was there into a harmless infinite yield loop.
func yieldLoopOverride(mem []byte, addr uint32) {
	copy(mem[addr:], ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysYield))
	brOff := int32(-8)
	copy(mem[addr+8:], ie64Instr(OP_BRA, 0, 0, 0, 0, 0, uint32(brOff)))
}

// overrideExtraTasks overrides tasks 2..N with yield loops so that CLOCK,
// CLIENT, etc. do not crash when the test has overridden CONSOLE/ECHO.
// Pass the full slice from findAllProgramImages; tasks at indices >= startIdx
// are overridden.
func overrideExtraTasks(mem []byte, images []uint32, startIdx int) {
	for i := startIdx; i < len(images); i++ {
		if images[i] >= 0x1000 && binary.LittleEndian.Uint32(mem[images[i]-0x1000:]) == elfMagicLE {
			header := images[i] - 0x1000
			phoff := binary.LittleEndian.Uint64(mem[header+32:])
			entry := header + uint32(phoff)
			filesz := binary.LittleEndian.Uint64(mem[entry+32:])
			if filesz < 16 {
				binary.LittleEndian.PutUint64(mem[entry+32:], 16)
			}
			memsz := binary.LittleEndian.Uint64(mem[entry+40:])
			if memsz < 0x1000 {
				binary.LittleEndian.PutUint64(mem[entry+40:], 0x1000)
			}
		} else {
			header := images[i] - imgHeaderSize
			if binary.LittleEndian.Uint32(mem[header+8:]) < 16 {
				binary.LittleEndian.PutUint32(mem[header+8:], 16)
			}
		}
		yieldLoopOverride(mem, images[i])
	}
}

func ensureImageCodeSizeAtLeast(t *testing.T, mem []byte, imageCodeStart uint32, minCodeBytes uint32) {
	t.Helper()
	headerStart, isELF := imageHeaderStartForCodeStart(t, mem, imageCodeStart)
	if isELF {
		phoff := binary.LittleEndian.Uint64(mem[headerStart+32:])
		phentsize := binary.LittleEndian.Uint16(mem[headerStart+54:])
		phnum := binary.LittleEndian.Uint16(mem[headerStart+56:])
		for i := uint16(0); i < phnum; i++ {
			codeEntry := headerStart + uint32(phoff) + uint32(i)*uint32(phentsize)
			if binary.LittleEndian.Uint32(mem[codeEntry:]) != 1 {
				continue
			}
			flags := binary.LittleEndian.Uint32(mem[codeEntry+4:])
			if flags&m14ELFSegFlagX == 0 {
				continue
			}
			if got := uint32(binary.LittleEndian.Uint64(mem[codeEntry+32:])); got < minCodeBytes {
				binary.LittleEndian.PutUint64(mem[codeEntry+32:], uint64(minCodeBytes))
			}
			if got := uint32(binary.LittleEndian.Uint64(mem[codeEntry+40:])); got < minCodeBytes {
				binary.LittleEndian.PutUint64(mem[codeEntry+40:], uint64(minCodeBytes))
			}
			return
		}
		t.Fatalf("ensureImageCodeSizeAtLeast: executable PT_LOAD not found at 0x%X", imageCodeStart)
	}
	if got := binary.LittleEndian.Uint32(mem[headerStart+8:]); got < minCodeBytes {
		binary.LittleEndian.PutUint32(mem[headerStart+8:], minCodeBytes)
	}
}

func writeTask0CodeScratch(t *testing.T, mem []byte, imageCodeStart uint32, scratchOff uint32, payload []byte) uint32 {
	t.Helper()
	if imageCodeStart >= 0x1000 && binary.LittleEndian.Uint32(mem[imageCodeStart-0x1000:]) == elfMagicLE {
		ensureImageCodeSizeAtLeast(t, mem, imageCodeStart, scratchOff+uint32(len(payload)))
	} else if imageCodeStart >= imgHeaderSize {
		var magic [8]byte
		binary.LittleEndian.PutUint32(magic[0:4], 0x34364549)
		binary.LittleEndian.PutUint32(magic[4:8], 0x474F5250)
		header := imageCodeStart - imgHeaderSize
		if bytes.Equal(mem[header:header+8], magic[:]) {
			ensureImageCodeSizeAtLeast(t, mem, imageCodeStart, scratchOff+uint32(len(payload)))
		}
	}
	copy(mem[imageCodeStart+scratchOff:], payload)
	return m164TestTask0CodeTarget + scratchOff
}

func writeLiveTaskCodeScratch(t *testing.T, mem []byte, taskCodeBase uint32, scratchOff uint32, payload []byte) uint32 {
	t.Helper()
	end := scratchOff + uint32(len(payload))
	if end > MMU_PAGE_SIZE {
		t.Fatalf("writeLiveTaskCodeScratch: scratch [%#x,%#x) exceeds live code page", scratchOff, end)
	}
	copy(mem[taskCodeBase+scratchOff:], payload)
	for taskID := uint64(0); taskID < maxTasks; taskID++ {
		if taskLayoutFieldQ(mem, taskID, kdTaskCodeBase) != uint64(taskCodeBase) {
			continue
		}
		startupBase := taskLayoutFieldQ(mem, taskID, kdTaskStartupBase)
		if startupBase != 0 {
			return uint32(binary.LittleEndian.Uint64(mem[uint32(startupBase)+taskStartupCodeBase:])) + scratchOff
		}
	}
	return taskCodeBase + scratchOff
}

func writeTaskImageLiteral(t *testing.T, mem []byte, imageCodeStart uint32, taskCodeBase uint32, scratchOff uint32, payload []byte) uint32 {
	t.Helper()
	ensureImageCodeSizeAtLeast(t, mem, imageCodeStart, scratchOff+uint32(len(payload)))
	copy(mem[imageCodeStart+scratchOff:], payload)
	return taskCodeBase + scratchOff
}

func writeTaskDataLiteral(t *testing.T, mem []byte, taskDataBase uint32, scratchOff uint32, payload []byte) uint32 {
	t.Helper()
	end := taskDataBase + scratchOff + uint32(len(payload))
	if end > uint32(len(mem)) {
		t.Fatalf("task data literal out of bounds: base=%#x off=%#x len=%d end=%#x mem=%#x", taskDataBase, scratchOff, len(payload), end, len(mem))
	}
	copy(mem[taskDataBase+scratchOff:end], payload)
	return taskDataBase + scratchOff
}

func taskSlotForPublicID(mem []byte, taskID uint64) (uint32, bool) {
	want := uint32(taskID)
	for slot := uint32(0); slot < maxTasks; slot++ {
		state := mem[kernDataBase+kdTCBBase+slot*tcbStride+tcbStateOff]
		if state == taskFree {
			continue
		}
		base := kernDataBase + kdTaskPubIDBase + slot*kdTaskPubIDStr
		if binary.LittleEndian.Uint32(mem[base:]) == want {
			return slot, true
		}
	}
	return 0, false
}

func countLiveTasks(mem []byte) int {
	count := 0
	for slot := uint32(0); slot < maxTasks; slot++ {
		if mem[kernDataBase+kdTCBBase+slot*tcbStride+tcbStateOff] != taskFree {
			count++
		}
	}
	return count
}

func taskLayoutFieldQ(mem []byte, taskID uint64, off uint32) uint64 {
	slot, ok := taskSlotForPublicID(mem, taskID)
	if !ok {
		return 0
	}
	base := kernDataBase + kdTaskLayoutBase + slot*kdTaskLayoutStr
	return binary.LittleEndian.Uint64(mem[base+off:])
}

func taskLayoutFieldL(mem []byte, taskID uint64, off uint32) uint32 {
	slot, ok := taskSlotForPublicID(mem, taskID)
	if !ok {
		return 0
	}
	base := kernDataBase + kdTaskLayoutBase + slot*kdTaskLayoutStr
	return binary.LittleEndian.Uint32(mem[base+off:])
}

func mustTaskDataBase(t *testing.T, mem []byte, taskID uint64) uint32 {
	t.Helper()

	dataBase := uint32(taskLayoutFieldQ(mem, taskID, kdTaskDataBase))
	startupBase := uint32(taskLayoutFieldQ(mem, taskID, kdTaskStartupBase))
	if startupBase != 0 {
		startupDataBase := uint32(binary.LittleEndian.Uint64(mem[startupBase+taskStartupDataBase:]))
		if startupDataBase != 0 {
			return startupDataBase
		}
	}

	if dataBase == 0 {
		t.Fatalf("task %d data base = 0, want non-zero", taskID)
	}

	return dataBase
}

func forceTaskExitOnNextRun(t *testing.T, mem []byte, taskID uint64) {
	t.Helper()

	slot, ok := taskSlotForPublicID(mem, taskID)
	if !ok {
		t.Fatalf("task %d is not live", taskID)
	}
	codeBase := uint32(taskLayoutFieldQ(mem, taskID, kdTaskCodeBase))
	if codeBase == 0 {
		t.Fatalf("task %d code base = 0", taskID)
	}

	copy(mem[codeBase:], ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysExitTask))
	copy(mem[codeBase+8:], ie64Instr(OP_BRA, 0, 0, 0, 0, 0, uint32(int32(codeBase+8)-int32(codeBase+8))))

	tcb := kernDataBase + kdTCBBase + slot*tcbStride
	binary.LittleEndian.PutUint64(mem[tcb+tcbPCOff:], uint64(codeBase))
	mem[tcb+tcbStateOff] = taskReady
	binary.LittleEndian.PutUint32(mem[tcb+tcbSigWaitOff:], 0)
	mem[tcb+tcbWaitPortOff] = 0
	mem[tcb+tcbGPRSavedOff] = 0
}

func bootAndResetToTask0Only(t *testing.T) (*ie64TestRig, *TerminalMMIO, uint32, uint32) {
	t.Helper()

	rig, term := assembleAndLoadKernel(t)
	return bootAndResetRigToTask0Only(t, rig, term)
}

func bootAndResetToTask0OnlyWithBootstrapHostRoot(t *testing.T, hostRoot string) (*ie64TestRig, *TerminalMMIO, uint32, uint32) {
	t.Helper()
	rig, term := assembleAndLoadKernelWithBootstrapHostRoot(t, hostRoot)
	return bootAndResetRigToTask0Only(t, rig, term)
}

func bootAndResetToTask0WithBootstrapHostRootPreservingServices(t *testing.T, hostRoot string) (*ie64TestRig, *TerminalMMIO, uint32, uint32) {
	t.Helper()
	rig, term := assembleAndLoadKernelWithBootstrapHostRoot(t, hostRoot)

	rig.cpu.running.Store(true)
	bootDone := make(chan struct{})
	go func() { rig.cpu.Execute(); close(bootDone) }()
	time.Sleep(2 * time.Second)
	rig.cpu.running.Store(false)
	<-bootDone

	term.DrainOutput()

	t0PubID := binary.LittleEndian.Uint32(rig.cpu.memory[kernDataBase+kdTaskPubIDBase:])
	t0 := uint32(taskLayoutFieldQ(rig.cpu.memory, uint64(t0PubID), kdTaskCodeBase))
	data0 := uint32(taskLayoutFieldQ(rig.cpu.memory, uint64(t0PubID), kdTaskDataBase))
	pt0 := uint32(taskLayoutFieldQ(rig.cpu.memory, uint64(t0PubID), kdTaskLayoutPT))
	usp0 := binary.LittleEndian.Uint64(rig.cpu.memory[kernDataBase+kdTCBBase+tcbUSPOff:])
	if t0 == 0 || data0 == 0 || pt0 == 0 || usp0 == 0 {
		t.Fatalf("bootAndResetToTask0WithBootstrapHostRootPreservingServices: missing live task0 layout pubid=%#x code=%#x data=%#x pt=%#x usp=%#x", t0PubID, t0, data0, pt0, usp0)
	}

	binary.LittleEndian.PutUint64(rig.cpu.memory[kernDataBase+kdCurrentTask:], 0)
	binary.LittleEndian.PutUint64(rig.cpu.memory[kernDataBase+kdTCBBase+tcbPCOff:], uint64(t0))
	binary.LittleEndian.PutUint32(rig.cpu.memory[kernDataBase+kdTCBBase+tcbSigWaitOff:], 0)
	rig.cpu.memory[kernDataBase+kdTCBBase+tcbStateOff] = taskRunning
	rig.cpu.memory[kernDataBase+kdTCBBase+tcbGPRSavedOff] = 0
	rig.cpu.PC = uint64(t0)
	rig.cpu.regs[31] = usp0
	rig.cpu.userSP = usp0
	rig.cpu.kernelSP = kernStackTop
	rig.cpu.ptbr = uint64(pt0)
	rig.cpu.supervisorMode = false
	rig.cpu.previousMode = false
	rig.cpu.trapped = false
	rig.cpu.faultCause = 0
	rig.cpu.faultAddr = 0
	rig.cpu.faultPC = 0
	rig.cpu.timerEnabled.Store(false)
	rig.cpu.interruptEnabled.Store(false)
	rig.cpu.timerCount.Store(0)

	return rig, term, t0, data0
}

func bootAndResetToShellTaskWithBootstrapHostRoot(t *testing.T, hostRoot string) (*ie64TestRig, *TerminalMMIO, uint32, uint32) {
	t.Helper()

	rig, term := assembleAndLoadKernelWithBootstrapHostRoot(t, hostRoot)
	rig.cpu.running.Store(true)
	bootDone := make(chan struct{})
	go func() { rig.cpu.Execute(); close(bootDone) }()
	time.Sleep(2 * time.Second)
	rig.cpu.running.Store(false)
	<-bootDone

	term.DrainOutput()

	layout, ok := tryFindShellTaskLayout(rig.cpu.memory)
	if !ok {
		t.Fatal("bootAndResetToShellTaskWithBootstrapHostRoot: could not locate shell public ID")
	}

	if layout.codeVA == 0 || layout.dataVA == 0 || layout.pt == 0 || layout.usp == 0 {
		t.Fatalf("bootAndResetToShellTaskWithBootstrapHostRoot: missing shell layout pubid=%#x code=%#x data=%#x pt=%#x usp=%#x", layout.pubid, layout.codeVA, layout.dataVA, layout.pt, layout.usp)
	}

	tcb := kernDataBase + kdTCBBase + layout.slot*tcbStride
	binary.LittleEndian.PutUint64(rig.cpu.memory[kernDataBase+kdCurrentTask:], uint64(layout.slot))
	binary.LittleEndian.PutUint64(rig.cpu.memory[tcb+tcbPCOff:], uint64(layout.codeVA))
	binary.LittleEndian.PutUint32(rig.cpu.memory[tcb+tcbSigWaitOff:], 0)
	rig.cpu.memory[tcb+tcbStateOff] = taskRunning
	rig.cpu.memory[tcb+tcbGPRSavedOff] = 0
	rig.cpu.PC = uint64(layout.codeVA)
	rig.cpu.regs[31] = layout.usp
	rig.cpu.userSP = layout.usp
	rig.cpu.kernelSP = kernStackTop
	rig.cpu.ptbr = uint64(layout.pt)
	rig.cpu.supervisorMode = false
	rig.cpu.previousMode = false
	rig.cpu.trapped = false
	rig.cpu.faultCause = 0
	rig.cpu.faultAddr = 0
	rig.cpu.faultPC = 0
	rig.cpu.timerEnabled.Store(false)
	rig.cpu.interruptEnabled.Store(false)
	rig.cpu.timerCount.Store(0)

	return rig, term, layout.codeVA, layout.dataVA
}

func bootAndResetRigToTask0Only(t *testing.T, rig *ie64TestRig, term *TerminalMMIO) (*ie64TestRig, *TerminalMMIO, uint32, uint32) {
	t.Helper()

	rig.cpu.running.Store(true)
	bootDone := make(chan struct{})
	go func() { rig.cpu.Execute(); close(bootDone) }()
	time.Sleep(500 * time.Millisecond)
	rig.cpu.running.Store(false)
	<-bootDone

	term.DrainOutput()

	t0PubID := binary.LittleEndian.Uint32(rig.cpu.memory[kernDataBase+kdTaskPubIDBase:])
	t0 := uint32(taskLayoutFieldQ(rig.cpu.memory, uint64(t0PubID), kdTaskCodeBase))
	data0 := uint32(taskLayoutFieldQ(rig.cpu.memory, uint64(t0PubID), kdTaskDataBase))
	pt0 := uint32(taskLayoutFieldQ(rig.cpu.memory, uint64(t0PubID), kdTaskLayoutPT))
	t0Target := m164TaskStartupTargetQ(t, rig.cpu.memory, uint64(t0PubID), taskStartupCodeBase)
	usp0 := binary.LittleEndian.Uint64(rig.cpu.memory[kernDataBase+kdTCBBase+tcbUSPOff:])
	if t0 == 0 || data0 == 0 || pt0 == 0 || usp0 == 0 {
		t.Fatalf("bootAndResetToTask0Only: missing live task0 layout pubid=%#x code=%#x data=%#x pt=%#x usp=%#x", t0PubID, t0, data0, pt0, usp0)
	}

	for slot := uint32(1); slot < maxTasks; slot++ {
		tcb := kernDataBase + kdTCBBase + slot*tcbStride
		rig.cpu.memory[tcb+tcbStateOff] = taskFree
		rig.cpu.memory[tcb+tcbGPRSavedOff] = 0
	}
	clear(rig.cpu.memory[kernDataBase+kdPortBase : kernDataBase+kdPortBase+kdPortStride*kdPortInlineMax])
	clear(rig.cpu.memory[kernDataBase+kdPortOflowHdr : kernDataBase+kdPortOflowHdr+16])
	binary.LittleEndian.PutUint64(rig.cpu.memory[kernDataBase+kdNumTasks:], 1)
	binary.LittleEndian.PutUint64(rig.cpu.memory[kernDataBase+kdCurrentTask:], 0)
	binary.LittleEndian.PutUint32(rig.cpu.memory[kernDataBase+kdHwresTask:], taskPubIDFree)
	clear(rig.cpu.memory[kernDataBase+kdModuleTable : kernDataBase+kdModuleTable+kdModuleRowStride*kdModuleMax])
	clear(rig.cpu.memory[kernDataBase+kdModuleWaiterRows : kernDataBase+kdModuleWaiterRows+kdModuleWaiterStride*kdModuleWaiterMax])
	clear(rig.cpu.memory[kernDataBase+kdModuleOpenRows : kernDataBase+kdModuleOpenRows+kdModuleOpenRowStride*kdModuleOpenRowMax])
	binary.LittleEndian.PutUint64(rig.cpu.memory[kernDataBase+kdTCBBase+tcbPCOff:], uint64(t0Target))
	binary.LittleEndian.PutUint32(rig.cpu.memory[kernDataBase+kdTCBBase+tcbSigWaitOff:], 0)
	binary.LittleEndian.PutUint32(rig.cpu.memory[kernDataBase+kdTCBBase+tcbSigRecvOff:], 0)
	rig.cpu.memory[kernDataBase+kdTCBBase+tcbStateOff] = taskRunning
	rig.cpu.memory[kernDataBase+kdTCBBase+tcbGPRSavedOff] = 0
	rig.cpu.PC = uint64(t0Target)
	rig.cpu.regs[31] = usp0
	rig.cpu.userSP = usp0
	rig.cpu.kernelSP = kernStackTop
	rig.cpu.ptbr = uint64(pt0)
	rig.cpu.supervisorMode = false
	rig.cpu.previousMode = false
	rig.cpu.trapped = false
	rig.cpu.faultCause = 0
	rig.cpu.faultAddr = 0
	rig.cpu.faultPC = 0
	rig.cpu.timerEnabled.Store(false)
	rig.cpu.interruptEnabled.Store(false)
	rig.cpu.timerCount.Store(0)

	return rig, term, t0, data0
}

func tryFindShellTaskDataBase(mem []byte) (uint32, bool) {
	for slot := uint32(0); slot < maxTasks; slot++ {
		state := mem[kernDataBase+kdTCBBase+slot*tcbStride+tcbStateOff]
		if state == taskFree {
			continue
		}
		pubid := binary.LittleEndian.Uint32(mem[kernDataBase+kdTaskPubIDBase+slot*kdTaskPubIDStr:])
		dataBase := uint32(taskLayoutFieldQ(mem, uint64(pubid), kdTaskDataBase))
		if dataBase == 0 {
			continue
		}
		dataPhys, ok := taskVAToPhys(mem, uint64(pubid), uint64(dataBase))
		if !ok || dataPhys+43 >= uint32(len(mem)) {
			continue
		}
		if bytes.HasPrefix(mem[dataPhys+32:dataPhys+43], []byte("Shell M10 [")) {
			return dataPhys, true
		}
	}
	return 0, false
}

type shellTaskLayout struct {
	slot     uint32
	pubid    uint32
	codeVA   uint32
	codePhys uint32
	dataVA   uint32
	dataPhys uint32
	pt       uint32
	usp      uint64
}

func tryFindShellTaskLayout(mem []byte) (shellTaskLayout, bool) {
	for slot := uint32(0); slot < maxTasks; slot++ {
		state := mem[kernDataBase+kdTCBBase+slot*tcbStride+tcbStateOff]
		if state == taskFree {
			continue
		}
		pubid := binary.LittleEndian.Uint32(mem[kernDataBase+kdTaskPubIDBase+slot*kdTaskPubIDStr:])
		dataBase := uint32(taskLayoutFieldQ(mem, uint64(pubid), kdTaskDataBase))
		if dataBase == 0 {
			continue
		}
		dataPhys, ok := taskVAToPhys(mem, uint64(pubid), uint64(dataBase))
		if !ok || dataPhys+43 >= uint32(len(mem)) {
			continue
		}
		if !bytes.HasPrefix(mem[dataPhys+32:dataPhys+43], []byte("Shell M10 [")) {
			continue
		}
		codeBase := taskLayoutFieldQ(mem, uint64(pubid), kdTaskCodeBase)
		runtimeDataBase := uint64(dataBase)
		if startupBase := taskLayoutFieldQ(mem, uint64(pubid), kdTaskStartupBase); startupBase != 0 {
			startupPhys := uint32(startupBase)
			if got := binary.LittleEndian.Uint64(mem[startupPhys+taskStartupCodeBase:]); got != 0 {
				codeBase = got
			}
			if got := binary.LittleEndian.Uint64(mem[startupPhys+taskStartupDataBase:]); got != 0 {
				runtimeDataBase = got
			}
		}
		codePhys, ok := taskVAToPhys(mem, uint64(pubid), codeBase)
		if !ok {
			continue
		}
		runtimeDataPhys, ok := taskVAToPhys(mem, uint64(pubid), runtimeDataBase)
		if !ok {
			continue
		}
		pt := uint32(taskLayoutFieldQ(mem, uint64(pubid), kdTaskLayoutPT))
		tcb := kernDataBase + kdTCBBase + slot*tcbStride
		usp := binary.LittleEndian.Uint64(mem[tcb+tcbUSPOff:])
		return shellTaskLayout{
			slot:     slot,
			pubid:    pubid,
			codeVA:   uint32(codeBase),
			codePhys: codePhys,
			dataVA:   uint32(runtimeDataBase),
			dataPhys: runtimeDataPhys,
			pt:       pt,
			usp:      usp,
		}, true
	}
	return shellTaskLayout{}, false
}

func tryFindShellTaskCodeBase(mem []byte) (uint32, bool) {
	layout, ok := tryFindShellTaskLayout(mem)
	if !ok {
		return 0, false
	}
	return layout.codePhys, true
}

func findShellTaskDataBase(t *testing.T, mem []byte) uint32 {
	t.Helper()
	dataBase, ok := tryFindShellTaskDataBase(mem)
	if !ok {
		t.Fatal("findShellTaskDataBase: could not locate live shell task")
	}
	return dataBase
}

func findTaskByDataMarker(mem []byte, marker byte) (uint64, bool) {
	for slot := uint32(0); slot < maxTasks; slot++ {
		state := mem[kernDataBase+kdTCBBase+slot*tcbStride+tcbStateOff]
		if state == taskFree {
			continue
		}
		base := kernDataBase + kdTaskLayoutBase + slot*kdTaskLayoutStr
		dataBase := binary.LittleEndian.Uint64(mem[base+kdTaskDataBase:])
		if dataBase == 0 {
			continue
		}
		pubid := binary.LittleEndian.Uint32(mem[kernDataBase+kdTaskPubIDBase+slot*kdTaskPubIDStr:])
		dataPhys, ok := taskVAToPhys(mem, uint64(pubid), dataBase)
		if !ok || dataPhys+64 >= uint32(len(mem)) {
			continue
		}
		if mem[dataPhys+64] != marker {
			continue
		}
		return uint64(pubid), true
	}
	return 0, false
}

func findTaskByCodePrefix(mem []byte, prefix []byte) (uint64, bool) {
	if len(prefix) == 0 {
		return 0, false
	}
	for slot := uint32(0); slot < maxTasks; slot++ {
		state := mem[kernDataBase+kdTCBBase+slot*tcbStride+tcbStateOff]
		if state == taskFree {
			continue
		}
		base := kernDataBase + kdTaskLayoutBase + slot*kdTaskLayoutStr
		codeBase := binary.LittleEndian.Uint64(mem[base+kdTaskCodeBase:])
		if codeBase == 0 || codeBase+uint64(len(prefix)) > uint64(len(mem)) {
			continue
		}
		if bytes.Equal(mem[uint32(codeBase):uint32(codeBase)+uint32(len(prefix))], prefix) {
			pubid := binary.LittleEndian.Uint32(mem[kernDataBase+kdTaskPubIDBase+slot*kdTaskPubIDStr:])
			return uint64(pubid), true
		}
	}
	return 0, false
}

func dumpActiveTaskState(mem []byte) string {
	var b strings.Builder
	for slot := uint32(0); slot < maxTasks; slot++ {
		state := mem[kernDataBase+kdTCBBase+slot*tcbStride+tcbStateOff]
		if state == taskFree {
			continue
		}
		pubid := binary.LittleEndian.Uint32(mem[kernDataBase+kdTaskPubIDBase+slot*kdTaskPubIDStr:])
		tcb := kernDataBase + kdTCBBase + slot*tcbStride
		pc := binary.LittleEndian.Uint64(mem[tcb+tcbPCOff:])
		dataBase := uint32(taskLayoutFieldQ(mem, uint64(pubid), kdTaskDataBase))
		label := ""
		if dataBase != 0 && dataBase+32 < uint32(len(mem)) {
			end := dataBase + 32
			for end < uint32(len(mem)) && end < dataBase+96 && mem[end] != 0 {
				end++
			}
			label = string(mem[dataBase+32 : end])
		}
		fmt.Fprintf(&b, "slot=%d pub=%d state=%d pc=0x%X data=0x%X label=%q\n", slot, pubid, state, pc, dataBase, label)
	}
	return b.String()
}

// memMultiLevelLeafPTE walks the multi-level page table at ptBase for the
// given VPN by indexing directly into the mem[] slice. Used by test
// helpers that read PT state outside a *CPU64 context. Returns 0 if any
// intermediate is unmapped or the address falls outside mem[].
func memMultiLevelLeafPTE(mem []byte, ptBase uint64, vpn uint64) uint64 {
	tableAddr := ptBase
	read64 := func(off uint64) (uint64, bool) {
		if off+8 > uint64(len(mem)) {
			return 0, false
		}
		return binary.LittleEndian.Uint64(mem[off:]), true
	}
	for level := 0; level < PT_LEVELS-1; level++ {
		var idx uint64
		if level == 0 {
			idx = (vpn >> 45) & PT_TOP_INDEX_MASK
		} else {
			shift := uint(9 * (5 - level))
			idx = (vpn >> shift) & PT_NODE_INDEX_MASK
		}
		pte, ok := read64(tableAddr + idx*8)
		if !ok {
			return 0
		}
		nextPPN, flags := parsePTE(pte)
		if flags&PTE_P == 0 {
			return 0
		}
		tableAddr = nextPPN << MMU_PAGE_SHIFT
	}
	leafIdx := vpn & PT_NODE_INDEX_MASK
	pte, ok := read64(tableAddr + leafIdx*8)
	if !ok {
		return 0
	}
	return pte
}

func taskVAToPhys(mem []byte, taskID uint64, va uint64) (uint32, bool) {
	slot, ok := taskSlotForPublicID(mem, taskID)
	if !ok {
		return 0, false
	}
	ptBase := binary.LittleEndian.Uint64(mem[kernDataBase+kdTaskLayoutBase+slot*kdTaskLayoutStr+kdTaskLayoutPT:])
	if ptBase == 0 {
		return 0, false
	}
	vpn := va >> MMU_PAGE_SHIFT
	pte := memMultiLevelLeafPTE(mem, ptBase, vpn)
	ppn, flags := parsePTE(pte)
	if flags&PTE_P == 0 {
		return 0, false
	}
	return uint32(ppn)<<MMU_PAGE_SHIFT | uint32(va&(MMU_PAGE_SIZE-1)), true
}

func taskVAPTEFlags(mem []byte, taskID uint64, va uint64) (byte, bool) {
	slot, ok := taskSlotForPublicID(mem, taskID)
	if !ok {
		return 0, false
	}
	ptBase := binary.LittleEndian.Uint64(mem[kernDataBase+kdTaskLayoutBase+slot*kdTaskLayoutStr+kdTaskLayoutPT:])
	if ptBase == 0 {
		return 0, false
	}
	vpn := va >> MMU_PAGE_SHIFT
	pte := memMultiLevelLeafPTE(mem, ptBase, vpn)
	_, flags := parsePTE(pte)
	return flags, true
}

func allocPoolFreePagesFromBitmap(mem []byte) uint32 {
	var used uint32
	base := kernDataBase + kdPageBitmap
	for i := uint32(0); i < allocPoolPages; i++ {
		b := mem[uint32(base)+i/8]
		if b&(1<<(i%8)) != 0 {
			used++
		}
	}
	return allocPoolPages - used
}

func allocPoolPageUsed(mem []byte, ppn uint32) bool {
	if ppn < allocPoolBase || ppn >= allocPoolBase+allocPoolPages {
		return false
	}
	bit := ppn - allocPoolBase
	b := mem[kernDataBase+kdPageBitmap+bit/8]
	return b&(1<<(bit%8)) != 0
}

func collectLiveTaskOwnedPoolPages(mem []byte) map[uint32]struct{} {
	owned := make(map[uint32]struct{})
	for slot := uint32(0); slot < maxTasks; slot++ {
		state := mem[kernDataBase+kdTCBBase+slot*tcbStride+tcbStateOff]
		if state == taskFree {
			continue
		}
		pubid := binary.LittleEndian.Uint32(mem[kernDataBase+kdTaskPubIDBase+slot*kdTaskPubIDStr:])
		if pubid == taskPubIDFree {
			continue
		}
		layout := kernDataBase + kdTaskLayoutBase + slot*kdTaskLayoutStr
		for _, field := range []struct {
			baseOff  uint32
			pagesOff uint32
		}{
			{kdTaskCodeBase, kdTaskCodePages},
			{kdTaskStackBase, kdTaskStackPages},
			{kdTaskDataBase, kdTaskDataPages},
		} {
			base := binary.LittleEndian.Uint64(mem[layout+field.baseOff:])
			pages := binary.LittleEndian.Uint32(mem[layout+field.pagesOff:])
			for i := uint32(0); i < pages; i++ {
				phys, ok := taskVAToPhys(mem, uint64(pubid), base+uint64(i)*MMU_PAGE_SIZE)
				if !ok {
					continue
				}
				owned[phys>>MMU_PAGE_SHIFT] = struct{}{}
			}
		}
		startupBase := binary.LittleEndian.Uint64(mem[layout+kdTaskStartupBase:])
		if startupBase != 0 {
			if phys, ok := taskVAToPhys(mem, uint64(pubid), startupBase); ok {
				owned[phys>>MMU_PAGE_SHIFT] = struct{}{}
			}
		}
		ptBase := binary.LittleEndian.Uint64(mem[layout+kdTaskLayoutPT:])
		if ptBase != 0 {
			owned[uint32(ptBase)>>MMU_PAGE_SHIFT] = struct{}{}
		}
	}
	return owned
}

func runM14LoadSegClient(t *testing.T, filename string, loops int, doUnload bool) (*ie64TestRig, uint32) {
	t.Helper()
	rig, _ := assembleAndLoadKernelWithBootstrapHostRootOptions(t, makeM152Phase5GeneratedHostRoot(t), false)
	return runM14LoadSegClientOnRig(t, rig, filename, loops, doUnload)
}

func runM14LoadSegClientOnRig(t *testing.T, rig *ie64TestRig, filename string, loops int, doUnload bool) (*ie64TestRig, uint32) {
	t.Helper()
	const (
		offDosPort    = 128
		offReplyPrt   = 136
		offBufferVA   = 144
		offShareHdl   = 152
		offLoadType   = 200
		offSeglistVA  = 208
		offUnloadType = 216
		offCounter    = 224
	)

	off := findShellClientCodeStart(t, rig.cpu.memory)
	w := func(instr []byte) { copy(rig.cpu.memory[off:], instr); off += 8 }

	w(ie64Instr(OP_SUB, 31, IE64_SIZE_L, 1, 31, 0, 16))
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 8))
	w(ie64Instr(OP_STORE, 29, IE64_SIZE_Q, 0, 31, 0, 0))

	findLoop := off
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	w(ie64Instr(OP_ADD, 1, IE64_SIZE_L, 1, 29, 0, 16))
	w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysFindPort))
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	beqInstr := off
	w(ie64Instr(OP_BEQ, 0, 0, 0, 2, 0, 0))
	w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysYield))
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	braFind := off
	w(ie64Instr(OP_BRA, 0, 0, 0, 0, 0, uint32(int32(findLoop)-int32(braFind))))
	foundDos := off
	copy(rig.cpu.memory[beqInstr:], ie64Instr(OP_BEQ, 0, 0, 0, 2, 0, uint32(int32(foundDos)-int32(beqInstr))))
	w(ie64Instr(OP_STORE, 1, IE64_SIZE_Q, 1, 29, 0, offDosPort))

	w(ie64Instr(OP_MOVE, 1, IE64_SIZE_L, 1, 0, 0, 0))
	w(ie64Instr(OP_MOVE, 2, IE64_SIZE_L, 1, 0, 0, 0))
	w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysCreatePort))
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	w(ie64Instr(OP_STORE, 1, IE64_SIZE_Q, 1, 29, 0, offReplyPrt))

	w(ie64Instr(OP_MOVE, 1, IE64_SIZE_L, 1, 0, 0, 4096))
	w(ie64Instr(OP_MOVE, 2, IE64_SIZE_L, 1, 0, 0, 0x10001))
	w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysAllocMem))
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	w(ie64Instr(OP_STORE, 1, IE64_SIZE_Q, 1, 29, 0, offBufferVA))
	w(ie64Instr(OP_STORE, 3, IE64_SIZE_Q, 1, 29, 0, offShareHdl))
	w(ie64Instr(OP_STORE, 0, IE64_SIZE_Q, 1, 29, 0, offCounter))

	loopTop := off
	w(ie64Instr(OP_LOAD, 10, IE64_SIZE_Q, 0, 29, 0, offCounter))
	w(ie64Instr(OP_MOVE, 28, IE64_SIZE_L, 1, 0, 0, uint32(loops)))
	bgeDone := off
	w(ie64Instr(OP_BGE, 0, 0, 0, 10, 28, 0))

	w(ie64Instr(OP_LOAD, 4, IE64_SIZE_Q, 0, 29, 0, offBufferVA))
	for i := 0; i < len(filename); i++ {
		w(ie64Instr(OP_MOVE, 5, IE64_SIZE_L, 1, 0, 0, uint32(filename[i])))
		w(ie64Instr(OP_STORE, 5, IE64_SIZE_B, 0, 4, 0, uint32(i)))
	}
	w(ie64Instr(OP_STORE, 0, IE64_SIZE_B, 0, 4, 0, uint32(len(filename))))

	w(ie64Instr(OP_LOAD, 1, IE64_SIZE_Q, 0, 29, 0, offDosPort))
	w(ie64Instr(OP_MOVE, 2, IE64_SIZE_L, 1, 0, 0, dosLoadSeg))
	w(ie64Instr(OP_MOVE, 3, IE64_SIZE_L, 1, 0, 0, 0))
	w(ie64Instr(OP_MOVE, 4, IE64_SIZE_L, 1, 0, 0, 0))
	w(ie64Instr(OP_LOAD, 5, IE64_SIZE_Q, 0, 29, 0, offReplyPrt))
	w(ie64Instr(OP_LOAD, 6, IE64_SIZE_L, 0, 29, 0, offShareHdl))
	w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysPutMsg))
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	w(ie64Instr(OP_LOAD, 1, IE64_SIZE_Q, 0, 29, 0, offReplyPrt))
	w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysWaitPort))
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	w(ie64Instr(OP_STORE, 1, IE64_SIZE_Q, 1, 29, 0, offLoadType))
	w(ie64Instr(OP_STORE, 2, IE64_SIZE_Q, 1, 29, 0, offSeglistVA))

	if doUnload {
		w(ie64Instr(OP_LOAD, 1, IE64_SIZE_Q, 0, 29, 0, offDosPort))
		w(ie64Instr(OP_MOVE, 2, IE64_SIZE_L, 1, 0, 0, dosUnLoadSeg))
		w(ie64Instr(OP_LOAD, 3, IE64_SIZE_Q, 0, 29, 0, offSeglistVA))
		w(ie64Instr(OP_MOVE, 4, IE64_SIZE_L, 1, 0, 0, 0))
		w(ie64Instr(OP_LOAD, 5, IE64_SIZE_Q, 0, 29, 0, offReplyPrt))
		w(ie64Instr(OP_LOAD, 6, IE64_SIZE_L, 0, 29, 0, offShareHdl))
		w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysPutMsg))
		w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
		w(ie64Instr(OP_LOAD, 1, IE64_SIZE_Q, 0, 29, 0, offReplyPrt))
		w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysWaitPort))
		w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
		w(ie64Instr(OP_STORE, 1, IE64_SIZE_Q, 1, 29, 0, offUnloadType))
	}

	w(ie64Instr(OP_LOAD, 10, IE64_SIZE_Q, 0, 29, 0, offCounter))
	w(ie64Instr(OP_ADD, 10, IE64_SIZE_L, 1, 10, 0, 1))
	w(ie64Instr(OP_STORE, 10, IE64_SIZE_Q, 1, 29, 0, offCounter))
	braTop := off
	w(ie64Instr(OP_BRA, 0, 0, 0, 0, 0, uint32(int32(loopTop)-int32(braTop))))
	loopDone := off
	copy(rig.cpu.memory[bgeDone:], ie64Instr(OP_BGE, 0, 0, 0, 10, 28, uint32(int32(loopDone)-int32(bgeDone))))

	yieldLoop := off
	w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysYield))
	braYield := off
	w(ie64Instr(OP_BRA, 0, 0, 0, 0, 0, uint32(int32(yieldLoop)-int32(braYield))))

	rig.cpu.running.Store(true)
	done := make(chan struct{})
	go func() { rig.cpu.Execute(); close(done) }()
	deadline := time.Now().Add(8 * time.Second)
	for time.Now().Before(deadline) {
		if dataBase, ok := tryFindShellTaskDataBase(rig.cpu.memory); ok {
			if binary.LittleEndian.Uint64(rig.cpu.memory[dataBase+offCounter:]) >= uint64(loops) {
				break
			}
		}
		time.Sleep(10 * time.Millisecond)
	}
	rig.cpu.running.Store(false)
	<-done

	dataBase := findShellTaskDataBase(t, rig.cpu.memory)
	return rig, dataBase
}

