func copyRepoFileToHostRoot(t *testing.T, hostRoot string, rel string, src string) {
	t.Helper()
	full := filepath.Join(hostRoot, "IOSSYS", filepath.FromSlash(rel))
	if err := os.MkdirAll(filepath.Dir(full), 0o755); err != nil {
		t.Fatal(err)
	}
	data, err := os.ReadFile(filepath.Join(repoRootDir(t), src))
	if err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(full, data, 0o644); err != nil {
		t.Fatal(err)
	}
}

func ensureHostRootBootDosLibrary(t *testing.T, hostRoot string) {
	t.Helper()
	if hostRoot == "" {
		return
	}
	info, err := os.Stat(hostRoot)
	if err != nil || !info.IsDir() {
		return
	}
	full := filepath.Join(hostRoot, "IOSSYS", "LIBS", "dos.library")
	if _, err := os.Stat(full); err == nil {
		return
	}
	if err := os.MkdirAll(filepath.Dir(full), 0o755); err != nil {
		t.Fatal(err)
	}
	data, err := os.ReadFile(filepath.Join(repoRootDir(t), "sdk", "intuitionos", "iexec", "boot_dos_library.elf"))
	if err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(full, data, 0o644); err != nil {
		t.Fatal(err)
	}
}

func copyDirTreeForTest(t *testing.T, srcRoot string, dstRoot string) {
	t.Helper()
	if err := filepath.WalkDir(srcRoot, func(path string, d os.DirEntry, err error) error {
		if err != nil {
			return err
		}
		rel, err := filepath.Rel(srcRoot, path)
		if err != nil {
			return err
		}
		target := filepath.Join(dstRoot, rel)
		if d.IsDir() {
			return os.MkdirAll(target, 0o755)
		}
		data, err := os.ReadFile(path)
		if err != nil {
			return err
		}
		if err := os.MkdirAll(filepath.Dir(target), 0o755); err != nil {
			return err
		}
		return os.WriteFile(target, data, 0o644)
	}); err != nil {
		t.Fatal(err)
	}
}

func makeM152Phase3HostRoot(t *testing.T) string {
	t.Helper()
	hostRoot := t.TempDir()
	for _, dir := range []string{
		"C", "S", "L", "LIBS", "DEVS", "RESOURCES",
	} {
		if err := os.MkdirAll(filepath.Join(hostRoot, "IOSSYS", dir), 0o755); err != nil {
			t.Fatal(err)
		}
	}
	if err := os.WriteFile(filepath.Join(hostRoot, "IOSSYS", "S", "Startup-Sequence"), []byte("ECHO phase3-host-startup\r\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(filepath.Join(hostRoot, "IOSSYS", "S", "Phase3-Only"), []byte("phase3-only\r\n"), 0o644); err != nil {
		t.Fatal(err)
	}
	copyRepoFileToHostRoot(t, hostRoot, "LIBS/dos.library", "sdk/intuitionos/iexec/boot_dos_library.elf")
	copyRepoFileToHostRoot(t, hostRoot, "C/Phase3Seg", "sdk/intuitionos/iexec/cmd_version.elf")
	copyRepoFileToHostRoot(t, hostRoot, "C/Version", "sdk/intuitionos/iexec/cmd_version.elf")
	return hostRoot
}

func makeM152Phase5GeneratedHostRoot(t *testing.T) string {
	t.Helper()
	hostRoot := t.TempDir()
	copyDirTreeForTest(t, filepath.Join(repoRootDir(t), "sdk", "intuitionos", "system", "SYS"), hostRoot)
	return hostRoot
}

func makeM16Phase1HostRoot(t *testing.T) string {
	t.Helper()
	hostRoot := makeM152Phase5GeneratedHostRoot(t)
	writeHostRootFileBytes(t, hostRoot, "S/Startup-Sequence", []byte("ECHO M16-PHASE1\r\n"))
	return hostRoot
}

func writeHostRootFileBytes(t *testing.T, hostRoot string, rel string, data []byte) {
	t.Helper()
	full := filepath.Join(hostRoot, "IOSSYS", filepath.FromSlash(rel))
	if err := os.MkdirAll(filepath.Dir(full), 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(full, data, 0o644); err != nil {
		t.Fatal(err)
	}
}

const (
	m16LibManifestSectionName = ".ios.manifest"
	m16LibManifestNoteName    = "IOS-MOD\x00"
	m16LibManifestNoteType    = 0x494F5331
	m16LibManifestMagic       = 0x4D534F49
	m16LibManifestDescSize    = 128
	m16ModfCompatPort         = 0x00000002
	m16ModfASLRCapable        = 0x00000004
)

type m16LibManifest struct {
	Magic       uint32
	DescVersion uint32
	Kind        uint8
	Name        string
	LibVersion  uint16
	LibRevision uint16
	Patch       uint16
	Type        uint32
	Flags       uint32
	MsgABIVer   uint32
}

func parseM16LibManifestNote(image []byte) (*m16LibManifest, error) {
	desc, err := m16FindIOSMDescriptor(image)
	if err != nil {
		return nil, err
	}
	nameBytes := desc[16:48]
	nameNul := bytes.IndexByte(nameBytes, 0)
	if nameNul < 0 {
		nameNul = len(nameBytes)
	}
	kind := desc[8]
	return &m16LibManifest{
		Magic:       binary.LittleEndian.Uint32(desc[0:4]),
		DescVersion: binary.LittleEndian.Uint32(desc[4:8]),
		Kind:        kind,
		Name:        string(nameBytes[:nameNul]),
		LibVersion:  binary.LittleEndian.Uint16(desc[10:12]),
		LibRevision: binary.LittleEndian.Uint16(desc[12:14]),
		Patch:       binary.LittleEndian.Uint16(desc[14:16]),
		Type:        uint32(kind),
		Flags:       binary.LittleEndian.Uint32(desc[48:52]),
		MsgABIVer:   binary.LittleEndian.Uint32(desc[52:56]),
	}, nil
}

func m16FindIOSMDescriptor(image []byte) ([]byte, error) {
	off, err := m16FindIOSMDescriptorOffset(image)
	if err != nil {
		return nil, err
	}
	return image[off : off+m16LibManifestDescSize], nil
}

func m16FindIOSMDescriptorOffset(image []byte) (int, error) {
	f, err := elf.NewFile(bytes.NewReader(image))
	if err != nil {
		return 0, err
	}
	var note []byte
	var noteFileOff uint64
	for _, prog := range f.Progs {
		if prog.Type != elf.PT_NOTE {
			continue
		}
		if note != nil {
			return 0, fmt.Errorf("multiple PT_NOTE program headers")
		}
		noteFileOff = prog.Off
		note = image[prog.Off : prog.Off+prog.Filesz]
	}
	if note == nil {
		return 0, fmt.Errorf("missing PT_NOTE")
	}
	for off := 0; off < len(note); {
		if len(note)-off < 12 {
			return 0, fmt.Errorf("note too small")
		}
		namesz := int(binary.LittleEndian.Uint32(note[off : off+4]))
		descsz := int(binary.LittleEndian.Uint32(note[off+4 : off+8]))
		typ := binary.LittleEndian.Uint32(note[off+8 : off+12])
		nameOff := off + 12
		nameEnd := nameOff + ((namesz + 3) &^ 3)
		descOff := nameEnd
		descEnd := descOff + ((descsz + 3) &^ 3)
		if namesz < 0 || descsz < 0 || nameEnd > len(note) || descEnd > len(note) {
			return 0, fmt.Errorf("note payload out of range")
		}
		if typ == m16LibManifestNoteType && string(note[nameOff:nameOff+namesz]) == m16LibManifestNoteName {
			if descsz != m16LibManifestDescSize {
				return 0, fmt.Errorf("descriptor size=%d, want %d", descsz, m16LibManifestDescSize)
			}
			return int(noteFileOff) + descOff, nil
		}
		off = descEnd
	}
	return 0, fmt.Errorf("missing IOS-MOD note")
}

func patchM16LibManifestMagic(t *testing.T, image []byte, magic uint32) []byte {
	t.Helper()
	patched := append([]byte(nil), image...)
	descOff, err := m16FindIOSMDescriptorOffset(patched)
	if err != nil {
		t.Fatalf("find IOSM: %v", err)
	}
	binary.LittleEndian.PutUint32(patched[descOff:], magic)
	return patched
}

func patchM16LibManifestCompatFields(t *testing.T, image []byte, version uint16, revision uint16, msgABIVer uint32) []byte {
	t.Helper()
	patched := append([]byte(nil), image...)
	descOff, err := m16FindIOSMDescriptorOffset(patched)
	if err != nil {
		t.Fatalf("find IOSM: %v", err)
	}
	binary.LittleEndian.PutUint16(patched[descOff+10:], version)
	binary.LittleEndian.PutUint16(patched[descOff+12:], revision)
	binary.LittleEndian.PutUint32(patched[descOff+52:], msgABIVer)
	return patched
}

func prependELFNoteSection(t *testing.T, image []byte) []byte {
	t.Helper()
	extraNote := []byte{
		0x04, 0x00, 0x00, 0x00, // namesz = 4
		0x04, 0x00, 0x00, 0x00, // descsz = 4
		0x03, 0x00, 0x00, 0x00, // type = NT_GNU_BUILD_ID-like
		'G', 'N', 'U', 0x00,
		'T', 'E', 'S', 'T',
	}
	return prependELFNoteBytes(t, image, extraNote)
}

func prependELFNoteBytes(t *testing.T, image []byte, extraNote []byte) []byte {
	t.Helper()
	f, err := elf.NewFile(bytes.NewReader(image))
	if err != nil {
		t.Fatalf("parse ELF: %v", err)
	}
	patched := append([]byte(nil), image...)
	for _, prog := range f.Progs {
		if prog.Type != elf.PT_NOTE {
			continue
		}
		start := int(prog.Off)
		end := start + int(prog.Filesz)
		newNote := append(append([]byte(nil), extraNote...), patched[start:end]...)
		patched = append(patched[:start], append(newNote, patched[end:]...)...)
		delta := uint64(len(extraNote))
		phoff := binary.LittleEndian.Uint64(patched[32:40])
		phentsize := binary.LittleEndian.Uint16(patched[54:56])
		phnum := binary.LittleEndian.Uint16(patched[56:58])
		for i := uint16(0); i < phnum; i++ {
			base := int(phoff) + int(i)*int(phentsize)
			typ := binary.LittleEndian.Uint32(patched[base : base+4])
			off := binary.LittleEndian.Uint64(patched[base+8 : base+16])
			if typ == uint32(elf.PT_NOTE) && off == prog.Off {
				binary.LittleEndian.PutUint64(patched[base+32:base+40], prog.Filesz+delta)
				binary.LittleEndian.PutUint64(patched[base+40:base+48], prog.Memsz+delta)
			} else if off > prog.Off {
				binary.LittleEndian.PutUint64(patched[base+8:base+16], off+delta)
			}
		}
		return patched
	}
	t.Fatal("missing PT_NOTE")
	return nil
}

func prependManifestSectionNote(t *testing.T, image []byte) []byte {
	t.Helper()
	return prependELFNoteSection(t, image)
}

func mustPatchBytesOnce(t *testing.T, data []byte, old string, new string) []byte {
	t.Helper()
	if len(old) != len(new) {
		t.Fatalf("mustPatchBytesOnce: patch length mismatch %q (%d) vs %q (%d)", old, len(old), new, len(new))
	}
	idx := bytes.Index(data, []byte(old))
	if idx < 0 {
		t.Fatalf("mustPatchBytesOnce: could not find %q", old)
	}
	patched := append([]byte(nil), data...)
	copy(patched[idx:idx+len(new)], []byte(new))
	return patched
}

func assembleKernelImageBytes(t *testing.T) []byte {
	t.Helper()
	asmBin := buildAssembler(t)
	tmpDir := t.TempDir()
	root := repoRootDir(t)
	copyFileForTest(t, filepath.Join(root, "sdk", "intuitionos", "iexec", "iexec.s"), filepath.Join(tmpDir, "iexec.s"))
	copyFileForTest(t, filepath.Join(root, "sdk", "include", "iexec.inc"), filepath.Join(tmpDir, "iexec.inc"))
	copyFileForTest(t, filepath.Join(root, "sdk", "include", "ie64.inc"), filepath.Join(tmpDir, "ie64.inc"))
	copyFileForTest(t, filepath.Join(root, "sdk", "include", "topaz.raw"), filepath.Join(tmpDir, "topaz.raw"))
	for _, name := range []string{
		"boot_console_handler.elf",
		"boot_dos_library.elf",
		"boot_shell.elf",
		"boot_hardware_resource.elf",
		"boot_input_device.elf",
		"boot_graphics_library.elf",
		"boot_intuition_library.elf",
		"cmd_version.elf",
		"cmd_avail.elf",
		"cmd_dir.elf",
		"cmd_type.elf",
		"cmd_echo.elf",
		"cmd_assign.elf",
		"cmd_list.elf",
		"cmd_which.elf",
		"cmd_help.elf",
		"cmd_gfxdemo.elf",
		"cmd_about.elf",
		"elfseg_fixture.elf",
	} {
		copyFileForTest(t, filepath.Join(root, "sdk", "intuitionos", "iexec", name), filepath.Join(tmpDir, name))
	}
	iexecSrcDir := filepath.Join(root, "sdk", "intuitionos", "iexec")
	cmd := exec.Command(asmBin, "-I", tmpDir, "-I", iexecSrcDir, filepath.Join(tmpDir, "iexec.s"))
	if out, err := cmd.CombinedOutput(); err != nil {
		t.Fatalf("assembly failed: %v\n%s", err, out)
	}
	data, err := os.ReadFile(filepath.Join(tmpDir, "iexec.ie64"))
	if err != nil {
		t.Fatalf("read assembled binary: %v", err)
	}
	return data
}

func encodeDOSAssignRow(t *testing.T, name string, target string) []byte {
	t.Helper()
	if len(name) == 0 || len(name) >= dosAssignNameMax {
		t.Fatalf("encodeDOSAssignRow: name %q length invalid", name)
	}
	if len(target) >= dosAssignNameMax {
		t.Fatalf("encodeDOSAssignRow: target %q length invalid", target)
	}
	row := make([]byte, dosAssignRowSz)
	copy(row[:dosAssignNameMax], []byte(name))
	copy(row[dosAssignTgtOff:], []byte(target))
	return row
}

func decodeDOSAssignRow(row []byte) (string, string) {
	nameEnd := bytes.IndexByte(row[:dosAssignNameMax], 0)
	if nameEnd < 0 {
		nameEnd = dosAssignNameMax
	}
	targetEnd := bytes.IndexByte(row[dosAssignTgtOff:dosAssignRowSz], 0)
	if targetEnd < 0 {
		targetEnd = dosAssignNameMax
	}
	return string(row[:nameEnd]), string(row[dosAssignTgtOff : dosAssignTgtOff+targetEnd])
}

func parseDOSAssignRows(t *testing.T, mem []byte, base uint32, count uint64) map[string]string {
	t.Helper()
	rows := make(map[string]string)
	for i := uint64(0); i < count; i++ {
		rowStart := base + uint32(i*dosAssignRowSz)
		row := mem[rowStart : rowStart+dosAssignRowSz]
		name, target := decodeDOSAssignRow(row)
		if name == "" {
			continue
		}
		rows[name] = target
	}
	return rows
}

func shellTaskSharedBuffer(t *testing.T, mem []byte, dataBase uint32, size uint32) []byte {
	t.Helper()
	bufVA := binary.LittleEndian.Uint64(mem[dataBase+144:])
	if bufVA == 0 {
		t.Fatal("shellTaskSharedBuffer: shared buffer VA is 0")
	}
	taskID := uint64(2)
	for slot := uint32(0); slot < maxTasks; slot++ {
		if mem[kernDataBase+kdTCBBase+slot*tcbStride+tcbStateOff] == taskFree {
			continue
		}
		pubid := binary.LittleEndian.Uint32(mem[kernDataBase+kdTaskPubIDBase+slot*kdTaskPubIDStr:])
		dataVA := taskLayoutFieldQ(mem, uint64(pubid), kdTaskDataBase)
		dataPhys, translated := taskVAToPhys(mem, uint64(pubid), dataVA)
		if translated && dataBase >= dataPhys && dataBase < dataPhys+0x1000 {
			taskID = uint64(pubid)
			break
		}
	}
	bufPhys, ok := taskVAToPhys(mem, taskID, bufVA)
	if ok && bufPhys+size <= uint32(len(mem)) {
		return mem[bufPhys : bufPhys+size]
	}
	for slot := uint32(0); slot < maxTasks; slot++ {
		if mem[kernDataBase+kdTCBBase+slot*tcbStride+tcbStateOff] == taskFree {
			continue
		}
		pubid := binary.LittleEndian.Uint32(mem[kernDataBase+kdTaskPubIDBase+slot*kdTaskPubIDStr:])
		phys, translated := taskVAToPhys(mem, uint64(pubid), bufVA)
		if !translated || phys+size > uint32(len(mem)) {
			continue
		}
		if !ok || bytes.IndexFunc(mem[phys:phys+size], func(r rune) bool { return r != 0 }) >= 0 {
			taskID = uint64(pubid)
			bufPhys = phys
			ok = true
			if bytes.IndexFunc(mem[phys:phys+size], func(r rune) bool { return r != 0 }) >= 0 {
				break
			}
		}
	}
	if !ok {
		t.Fatalf("shellTaskSharedBuffer: could not translate buffer VA 0x%X for task %d", bufVA, taskID)
	}
	return mem[bufPhys : bufPhys+size]
}

func runDOSAssignClient(t *testing.T, op uint32, input []byte) (*ie64TestRig, uint32) {
	t.Helper()
	if len(input) > 512 {
		t.Fatalf("runDOSAssignClient: input length %d too large", len(input))
	}
	const (
		offDosPort    = 896
		offReplyPrt   = 904
		offBufferVA   = 912
		offShareHdl   = 920
		offReplyType  = 928
		offReplyData0 = 936
	)

	rig, _ := bootRigWithPatchedHostShellELF(t, func(image []byte) {
		patchHostShellELFWithDOSAssignClient(t, image, op, input)
	})

	rig.cpu.running.Store(true)
	done := make(chan struct{})
	go func() { rig.cpu.Execute(); close(done) }()
	time.Sleep(2 * time.Second)
	rig.cpu.running.Store(false)
	<-done

	return rig, findShellTaskDataBase(t, rig.cpu.memory) + 768
}

func runDOSRunClientOnRig(t *testing.T, rig *ie64TestRig, input []byte) (*ie64TestRig, uint32) {
	t.Helper()
	if len(input) > 512 {
		t.Fatalf("runDOSRunClientOnRig: input length %d too large", len(input))
	}
	const (
		offDosPort    = 128
		offReplyPrt   = 136
		offBufferVA   = 144
		offShareHdl   = 152
		offReplyType  = 160
		offReplyData0 = 168
	)

	shellCode := findShellClientCodeStart(t, rig.cpu.memory)
	liveShell, hasLiveShell := tryFindShellTaskLayout(rig.cpu.memory)
	if hasLiveShell {
		shellCode = liveShell.codePhys
	}
	off := shellCode
	w := func(instr []byte) { copy(rig.cpu.memory[off:], instr); off += 8 }
	writeBytesAtBuffer := func(data []byte) {
		w(ie64Instr(OP_LOAD, 4, IE64_SIZE_Q, 0, 29, 0, offBufferVA))
		for i, b := range data {
			w(ie64Instr(OP_MOVE, 5, IE64_SIZE_L, 1, 0, 0, uint32(b)))
			w(ie64Instr(OP_STORE, 5, IE64_SIZE_B, 0, 4, 0, uint32(i)))
		}
	}

	w(ie64Instr(OP_SUB, 31, IE64_SIZE_L, 1, 31, 0, 16))
	if hasLiveShell {
		w(ie64Instr(OP_MOVE, 29, IE64_SIZE_L, 1, 0, 0, liveShell.dataVA))
	} else {
		w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 8))
	}
	w(ie64Instr(OP_STORE, 29, IE64_SIZE_Q, 0, 31, 0, 0))

	findLoop := off
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	w(ie64Instr(OP_ADD, 1, IE64_SIZE_L, 1, 29, 0, 16))
	w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysFindPort))
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	beqInstr := off
	w(ie64Instr(OP_BEQ, 0, 0, 0, 2, 0, 0))
	w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysYield))
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	braFind := off
	w(ie64Instr(OP_BRA, 0, 0, 0, 0, 0, uint32(int32(findLoop)-int32(braFind))))
	foundDos := off
	copy(rig.cpu.memory[beqInstr:], ie64Instr(OP_BEQ, 0, 0, 0, 2, 0, uint32(int32(foundDos)-int32(beqInstr))))
	w(ie64Instr(OP_STORE, 1, IE64_SIZE_Q, 1, 29, 0, offDosPort))

	w(ie64Instr(OP_MOVE, 1, IE64_SIZE_L, 1, 0, 0, 0))
	w(ie64Instr(OP_MOVE, 2, IE64_SIZE_L, 1, 0, 0, 0))
	w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysCreatePort))
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	w(ie64Instr(OP_STORE, 1, IE64_SIZE_Q, 1, 29, 0, offReplyPrt))

	w(ie64Instr(OP_MOVE, 1, IE64_SIZE_L, 1, 0, 0, 4096))
	w(ie64Instr(OP_MOVE, 2, IE64_SIZE_L, 1, 0, 0, 0x10001))
	w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysAllocMem))
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	w(ie64Instr(OP_STORE, 1, IE64_SIZE_Q, 1, 29, 0, offBufferVA))
	w(ie64Instr(OP_STORE, 3, IE64_SIZE_Q, 1, 29, 0, offShareHdl))

	if len(input) > 0 {
		writeBytesAtBuffer(input)
	}
	w(ie64Instr(OP_LOAD, 1, IE64_SIZE_Q, 0, 29, 0, offDosPort))
	w(ie64Instr(OP_MOVE, 2, IE64_SIZE_L, 1, 0, 0, dosRun))
	w(ie64Instr(OP_MOVE, 3, IE64_SIZE_L, 1, 0, 0, 0))
	w(ie64Instr(OP_MOVE, 4, IE64_SIZE_L, 1, 0, 0, 0))
	w(ie64Instr(OP_LOAD, 5, IE64_SIZE_Q, 0, 29, 0, offReplyPrt))
	w(ie64Instr(OP_LOAD, 6, IE64_SIZE_L, 0, 29, 0, offShareHdl))
	w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysPutMsg))
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	w(ie64Instr(OP_LOAD, 1, IE64_SIZE_Q, 0, 29, 0, offReplyPrt))
	w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysWaitPort))
	w(ie64Instr(OP_LOAD, 29, IE64_SIZE_Q, 0, 31, 0, 0))
	w(ie64Instr(OP_STORE, 1, IE64_SIZE_Q, 1, 29, 0, offReplyType))
	w(ie64Instr(OP_STORE, 2, IE64_SIZE_Q, 1, 29, 0, offReplyData0))

	loopHere := off
	w(ie64Instr(OP_SYSCALL, 0, 0, 1, 0, 0, sysYield))
	braLoop := off
	w(ie64Instr(OP_BRA, 0, 0, 0, 0, 0, uint32(int32(loopHere)-int32(braLoop))))

	clientSize := off - shellCode
	if clientSize > 3256 {
		t.Fatalf("runDOSRunClientOnRig: test client too large: %d > 3256", clientSize)
	}

	if hasLiveShell {
		tcb := kernDataBase + kdTCBBase + liveShell.slot*tcbStride
		binary.LittleEndian.PutUint64(rig.cpu.memory[kernDataBase+kdCurrentTask:], uint64(liveShell.slot))
		binary.LittleEndian.PutUint64(rig.cpu.memory[tcb+tcbPCOff:], uint64(liveShell.codeVA))
		binary.LittleEndian.PutUint32(rig.cpu.memory[tcb+tcbSigWaitOff:], 0)
		binary.LittleEndian.PutUint32(rig.cpu.memory[tcb+tcbSigRecvOff:], 0)
		rig.cpu.memory[tcb+tcbStateOff] = taskRunning
		rig.cpu.memory[tcb+tcbGPRSavedOff] = 0
		rig.cpu.PC = uint64(liveShell.codeVA)
		rig.cpu.regs[31] = liveShell.usp
		rig.cpu.userSP = liveShell.usp
		rig.cpu.kernelSP = kernStackTop
		rig.cpu.ptbr = uint64(liveShell.pt)
		rig.cpu.supervisorMode = false
		rig.cpu.previousMode = false
		rig.cpu.trapped = false
		rig.cpu.faultCause = 0
		rig.cpu.faultAddr = 0
		rig.cpu.faultPC = 0
		rig.cpu.timerEnabled.Store(false)
		rig.cpu.interruptEnabled.Store(false)
		rig.cpu.timerCount.Store(0)
	}

	rig.cpu.running.Store(true)
	done := make(chan struct{})
	go func() { rig.cpu.Execute(); close(done) }()
	time.Sleep(2500 * time.Millisecond)
	rig.cpu.running.Store(false)
	<-done

	if hasLiveShell {
		return rig, liveShell.dataPhys
	}
	return rig, findShellTaskDataBase(t, rig.cpu.memory)
}

