func assertFullBootStackServiceCensus(t *testing.T) {
	t.Helper()
	rig, term := assembleAndLoadKernelWithGeneratedHostRoot(t)
	rig.cpu.running.Store(true)
	done := make(chan struct{})
	go func() { rig.cpu.Execute(); close(done) }()
	time.Sleep(5 * time.Second)
	rig.cpu.running.Store(false)
	<-done

	output := term.DrainOutput()
	for _, want := range []string{
		"IntuitionOS 1.16.7",
		"Type HELP for commands and ASSIGN for layout",
		"1>",
	} {
		if !strings.Contains(output, want) {
			t.Fatalf("Phase5_FullBootStack_ServiceCensus: missing %q in output=%q", want, output[:min(len(output), 800)])
		}
	}

	mem := rig.cpu.memory
	wantPorts := []string{
		"console.handler",
		"dos.library",
		"hardware.resource",
		"input.device",
	}
	for _, want := range wantPorts {
		if !testPortTableHasPublicName(mem, want) {
			t.Fatalf("Phase5_FullBootStack_ServiceCensus: missing public port %q", want)
		}
	}
	for _, unwanted := range []string{
		"graphics.library",
		"intuition.library",
	} {
		if testPortTableHasPublicName(mem, unwanted) {
			t.Fatalf("Phase5_FullBootStack_ServiceCensus: unexpected public port %q during text-mode boot", unwanted)
		}
	}
}

