		if mem[portBase+kdPortValid] == 0 {
			continue
		}
		if mem[portBase+kdPortFlags]&pfPublic == 0 {
			continue
		}
		name := strings.TrimRight(string(mem[portBase+kdPortName:portBase+kdPortName+portNameLen]), "\x00")
