	rig, dataBase := runDOSAssignSequenceClient(t, []dosAssignStep{
		{op: dosAssignOpAdd, input: encodeDOSAssignRow(t, "C", "T/")},
		{op: dosAssignOpLayeredQuery, input: append([]byte("C"), 0)},
	})
